"""Filter, roll up, and merge alert intervals."""

from __future__ import annotations

from datetime import datetime, timedelta

import pandas as pd

from air_raid_alerts.regions import RegionSpec, get_region
from air_raid_alerts.schema import EventCol, IntervalCol, MERGED_INTERVAL_COLUMNS


def filter_region_events(events: pd.DataFrame, region_id: str) -> pd.DataFrame:
    """Keep rows matching the region registry oblast filter."""
    spec = get_region(region_id)
    mask = events[EventCol.OBLAST] == spec.vadimkin_oblast
    filtered = events.loc[mask].copy()
    filtered[EventCol.REGION_ID] = region_id
    return filtered.reset_index(drop=True)


def _to_interval_pairs(events: pd.DataFrame) -> list[tuple[datetime, datetime | None]]:
    pairs: list[tuple[datetime, datetime | None]] = []
    for _, row in events.iterrows():
        pairs.append((row[EventCol.STARTED_AT], row[EventCol.FINISHED_AT]))
    return pairs


def merge_intervals(
    intervals: list[tuple[datetime, datetime | None]],
    *,
    data_cutoff: datetime | None = None,
) -> list[tuple[datetime, datetime]]:
    """
    Merge overlapping alert intervals.

    Alert active for all τ with started_at ≤ τ ≤ finished_at (inclusive end).
    Open-ended intervals (finished_at is None) are treated as active until
    data_cutoff when provided.
    """
    if not intervals:
        return []

    normalized: list[tuple[datetime, datetime]] = []
    for start, end in intervals:
        if end is None:
            if data_cutoff is None:
                raise ValueError("Open-ended interval requires data_cutoff")
            end = data_cutoff
        if end < start:
            raise ValueError(f"finished_at < started_at: {start} > {end}")
        normalized.append((start, end))

    normalized.sort(key=lambda item: item[0])
    merged: list[tuple[datetime, datetime]] = [normalized[0]]

    for start, end in normalized[1:]:
        last_start, last_end = merged[-1]
        if start <= last_end:
            merged[-1] = (last_start, max(last_end, end))
        else:
            merged.append((start, end))

    return merged


def build_merged_intervals(
    events: pd.DataFrame,
    region_id: str,
    *,
    data_cutoff: datetime | None = None,
) -> pd.DataFrame:
    """
    Full interval pipeline: filter → optional oblast rollup → merge overlaps.

    Returns one row per disjoint merged interval with region_id set.
    """
    filtered = filter_region_events(events, region_id)
    if filtered.empty:
        return pd.DataFrame(columns=list(MERGED_INTERVAL_COLUMNS))

    pairs = _to_interval_pairs(filtered)
    merged = merge_intervals(pairs, data_cutoff=data_cutoff)

    rows = []
    for start, end in merged:
        outlier = end - start > timedelta(days=7)
        rows.append(
            {
                IntervalCol.REGION_ID: region_id,
                IntervalCol.STARTED_AT: start,
                IntervalCol.FINISHED_AT: end,
                IntervalCol.IS_OUTLIER_DURATION: outlier,
            }
        )

    return pd.DataFrame(rows)


def rollup_mode_for_region(region_id: str) -> RegionSpec:
    return get_region(region_id)

"""Hourly activity panel and exposure labels."""

from __future__ import annotations

from datetime import UTC, datetime, timedelta

import pandas as pd

from air_raid_alerts.schema import (
    EventCol,
    IntervalCol,
    PANEL_COLUMNS,
    PanelCol,
    exposure_label,
)

HOUR = timedelta(hours=1)


def hour_floor(ts: datetime) -> datetime:
    ts = ts.astimezone(UTC)
    return ts.replace(minute=0, second=0, microsecond=0)


def is_active_in_hour(
    intervals: pd.DataFrame,
    hour_start: datetime,
) -> bool:
    """
    Hourly active(r, t) with convention [t, t+1h).

    True if ∃ τ with started_at ≤ τ ≤ finished_at and τ ∈ [hour_start, hour_start + 1h).
    """
    hour_end = hour_start + HOUR
    for _, row in intervals.iterrows():
        start = row[IntervalCol.STARTED_AT]
        end = row[IntervalCol.FINISHED_AT]
        if start < hour_end and end > hour_start:
            return True
    return False


def exposure_in_forward_window(
    intervals: pd.DataFrame,
    origin: datetime,
    horizon_hours: int,
) -> bool:
    """
    y_r,N(t) = 1 if ∃ τ ∈ (t, t+N] with region under alert.

    Uses inclusive alert end and open-left forecast window per REQUIREMENTS.md.
    """
    if horizon_hours < 1:
        raise ValueError("horizon_hours must be >= 1")

    window_end = origin + timedelta(hours=horizon_hours)
    for _, row in intervals.iterrows():
        start = row[IntervalCol.STARTED_AT]
        end = row[IntervalCol.FINISHED_AT]
        # Overlap of [start, end] with (origin, window_end]
        if start <= window_end and end > origin:
            return True
    return False


def build_hourly_origins(
    range_start: datetime,
    range_end: datetime,
) -> pd.DatetimeIndex:
    """Hourly forecast origins from range_start (inclusive) to range_end (exclusive)."""
    start = hour_floor(range_start)
    end = hour_floor(range_end)
    if end <= start:
        return pd.DatetimeIndex([], tz="UTC")
    return pd.date_range(start=start, end=end - HOUR, freq="h", tz="UTC")


def build_hourly_panel(
    intervals: pd.DataFrame,
    range_start: datetime,
    range_end: datetime,
) -> pd.DataFrame:
    """Build hourly active flags for merged intervals."""
    origins = build_hourly_origins(range_start, range_end)
    if len(origins) == 0:
        return pd.DataFrame(columns=list(PANEL_COLUMNS))

    region_id = intervals[IntervalCol.REGION_ID].iloc[0] if not intervals.empty else None
    rows = []
    for origin in origins:
        origin_dt = origin.to_pydatetime()
        rows.append(
            {
                PanelCol.REGION_ID: region_id,
                PanelCol.ORIGIN_HOUR: origin_dt,
                PanelCol.ACTIVE: int(is_active_in_hour(intervals, origin_dt)),
            }
        )
    return pd.DataFrame(rows)


def build_exposure_labels(
    intervals: pd.DataFrame,
    origins: pd.DatetimeIndex | pd.Series,
    horizons: range | list[int] | None = None,
) -> pd.DataFrame:
    """Build y_r,N for each origin hour and horizon N."""
    if horizons is None:
        horizons = range(1, 25)

    rows = []
    region_id = intervals[IntervalCol.REGION_ID].iloc[0] if not intervals.empty else None
    for origin in origins:
        origin_dt = pd.Timestamp(origin).to_pydatetime()
        row: dict = {PanelCol.REGION_ID: region_id, PanelCol.ORIGIN_HOUR: origin_dt}
        for horizon in horizons:
            row[exposure_label(horizon)] = int(
                exposure_in_forward_window(intervals, origin_dt, horizon)
            )
        rows.append(row)

    return pd.DataFrame(rows)

"""Raw and transformed data quality checks."""

from __future__ import annotations

import json
from pathlib import Path

import pandas as pd

from air_raid_alerts.ingest.fetch_vadimkin import validate_csv
from air_raid_alerts.schema import (
    EXPECTED_COLUMNS,
    EventCol,
    IntervalCol,
    exposure_label,
)
from air_raid_alerts.transform.clean import load_vadimkin_events


def load_manifest(manifest_path: Path) -> dict:
    with manifest_path.open(encoding="utf-8") as handle:
        return json.load(handle)


def validate_raw_against_manifest(
    csv_path: Path,
    manifest_path: Path,
    *,
    row_count_tolerance: float = 0.01,
) -> list[str]:
    """Return a list of validation errors (empty if OK)."""
    errors: list[str] = []
    manifest = load_manifest(manifest_path)

    expected_columns = manifest.get("columns", list(EXPECTED_COLUMNS))
    if list(expected_columns) != list(EXPECTED_COLUMNS):
        errors.append("Manifest columns do not match expected Vadimkin schema")

    try:
        row_count = validate_csv(csv_path)
    except ValueError as exc:
        errors.append(str(exc))
        return errors

    manifest_rows = manifest.get("row_count")
    if manifest_rows is not None:
        delta = abs(row_count - manifest_rows) / max(manifest_rows, 1)
        if delta > row_count_tolerance:
            errors.append(
                f"Row count {row_count} differs from manifest {manifest_rows} "
                f"by {delta:.2%} (tolerance {row_count_tolerance:.0%})"
            )

    return errors


def validate_event_durations(events: pd.DataFrame) -> list[str]:
    errors: list[str] = []
    for idx, row in events.iterrows():
        finished = row[EventCol.FINISHED_AT]
        if finished is not None and finished < row[EventCol.STARTED_AT]:
            errors.append(f"Row {idx}: finished_at < started_at")
    return errors


def validate_merged_intervals(intervals: pd.DataFrame) -> list[str]:
    errors: list[str] = []
    if intervals.empty:
        return errors

    previous_end = None
    for idx, row in intervals.iterrows():
        if row[IntervalCol.FINISHED_AT] < row[IntervalCol.STARTED_AT]:
            errors.append(f"Interval {idx}: finished_at < started_at")
        if previous_end is not None and row[IntervalCol.STARTED_AT] <= previous_end:
            errors.append(f"Interval {idx}: overlaps previous merged interval")
        previous_end = row[IntervalCol.FINISHED_AT]

    return errors


def assert_labels_match_intervals(
    intervals: pd.DataFrame,
    origin_hour: datetime,
    horizon_hours: int,
    label_value: int,
) -> None:
    """
    Verify y_r,N(t) is consistent with merged intervals and DATA.md window (t, t+N].

    Labels may use alert state after origin t (exposure target); this checks
    consistency of the label function, not feature leakage.
    """
    from air_raid_alerts.transform.panel import exposure_in_forward_window

    expected = int(exposure_in_forward_window(intervals, origin_hour, horizon_hours))
    if expected != label_value:
        raise AssertionError(
            f"Label {exposure_label(horizon_hours)} at {origin_hour} "
            f"expected {expected}, got {label_value}"
        )

