"""Per-horizon logistic exposure models."""

from __future__ import annotations

from dataclasses import dataclass

import pandas as pd
from sklearn.impute import SimpleImputer
from sklearn.linear_model import LogisticRegression
from sklearn.pipeline import Pipeline
from sklearn.preprocessing import StandardScaler

from air_raid_alerts.models.baselines import label_horizons
from air_raid_alerts.schema import PanelCol, ProcessedCol, exposure_label, is_exposure_label


def model_prediction_column(horizon_hours: int) -> str:
    return f"pred_{exposure_label(horizon_hours)}"


def feature_columns_from_matrix(training_matrix: pd.DataFrame) -> list[str]:
    excluded = {
        PanelCol.REGION_ID,
        PanelCol.ORIGIN_HOUR,
        ProcessedCol.SPLIT,
        ProcessedCol.IN_PRIMARY_TRAIN,
    }
    return [
        column
        for column in training_matrix.columns
        if column not in excluded and not is_exposure_label(column)
    ]


def primary_train_mask(training_matrix: pd.DataFrame) -> pd.Series:
    if ProcessedCol.IN_PRIMARY_TRAIN not in training_matrix.columns:
        raise ValueError(f"Missing column: {ProcessedCol.IN_PRIMARY_TRAIN}")
    return training_matrix[ProcessedCol.IN_PRIMARY_TRAIN].astype(bool)


def test_split_mask(training_matrix: pd.DataFrame) -> pd.Series:
    if ProcessedCol.SPLIT not in training_matrix.columns:
        raise ValueError(f"Missing column: {ProcessedCol.SPLIT}")
    return training_matrix[ProcessedCol.SPLIT] == "test"


def _make_pipeline() -> Pipeline:
    return Pipeline(
        steps=[
            ("imputer", SimpleImputer(strategy="median")),
            ("scaler", StandardScaler()),
            (
                "classifier",
                LogisticRegression(max_iter=2000, class_weight="balanced"),
            ),
        ]
    )


@dataclass(frozen=True)
class FittedExposureModel:
    region_id: str
    horizons: tuple[int, ...]
    feature_columns: tuple[str, ...]
    pipelines: dict[int, Pipeline]

    def predict(self, rows: pd.DataFrame) -> pd.DataFrame:
        missing = set(self.feature_columns) - set(rows.columns)
        if missing:
            raise ValueError(f"Missing feature columns: {sorted(missing)}")

        features = rows.loc[:, list(self.feature_columns)]
        predictions: dict[str, pd.Series] = {}
        for horizon in self.horizons:
            pipeline = self.pipelines[horizon]
            probabilities = pipeline.predict_proba(features)[:, 1]
            column = model_prediction_column(horizon)
            predictions[column] = pd.Series(probabilities, index=rows.index)
        return pd.DataFrame(predictions, index=rows.index)


def fit_exposure_model(
    training_matrix: pd.DataFrame,
    region_id: str,
    *,
    horizons: range | list[int] | None = None,
    fit_mask: pd.Series | None = None,
) -> FittedExposureModel:
    """Fit one logistic regression per horizon on the provided training rows."""
    feature_columns = feature_columns_from_matrix(training_matrix)
    if not feature_columns:
        raise ValueError("No feature columns found in training matrix")

    horizon_list = list(horizons) if horizons is not None else label_horizons(training_matrix)
    mask = fit_mask if fit_mask is not None else primary_train_mask(training_matrix)
    fit_df = training_matrix.loc[mask]
    if fit_df.empty:
        raise ValueError("No training rows available to fit exposure model")

    features = fit_df.loc[:, feature_columns]
    pipelines: dict[int, Pipeline] = {}
    for horizon in horizon_list:
        label = exposure_label(horizon)
        if label not in fit_df.columns:
            raise ValueError(f"Missing label column: {label}")

        pipeline = _make_pipeline()
        pipeline.fit(features, fit_df[label])
        pipelines[horizon] = pipeline

    return FittedExposureModel(
        region_id=region_id,
        horizons=tuple(horizon_list),
        feature_columns=tuple(feature_columns),
        pipelines=pipelines,
    )

"""Probability calibration for fitted exposure models."""

from __future__ import annotations

from typing import Literal

import numpy as np
import pandas as pd
from sklearn.calibration import CalibratedClassifierCV
from sklearn.isotonic import IsotonicRegression
from sklearn.pipeline import Pipeline

from air_raid_alerts.models.exposure import FittedExposureModel, validation_split_mask
from air_raid_alerts.schema import exposure_label

CalibrationMethod = Literal["isotonic", "sigmoid"]


class _IdentityCalibrator:
    """Pass-through calibrator when validation data cannot support isotonic fit."""

    def predict(self, probabilities: np.ndarray) -> np.ndarray:
        return np.clip(probabilities, 0.0, 1.0)


def _fit_horizon_calibrator(
    raw_probabilities: np.ndarray,
    labels: np.ndarray,
    *,
    method: CalibrationMethod,
) -> IsotonicRegression | _IdentityCalibrator | CalibratedClassifierCV:
    labels = np.asarray(labels, dtype=np.int8)
    raw_probabilities = np.clip(np.asarray(raw_probabilities, dtype=np.float64), 0.0, 1.0)

    if len(np.unique(labels)) < 2:
        return _IdentityCalibrator()

    if method == "isotonic":
        calibrator = IsotonicRegression(out_of_bounds="clip")
        calibrator.fit(raw_probabilities, labels)
        return calibrator

    # Platt scaling via sigmoid on a single feature (raw probability).
    platt = Pipeline(
        steps=[
            (
                "classifier",
                __import__("sklearn.linear_model", fromlist=["LogisticRegression"]).LogisticRegression(
                    max_iter=1000
                ),
            )
        ]
    )
    platt.fit(raw_probabilities.reshape(-1, 1), labels)
    return platt


def _apply_horizon_calibrator(
    calibrator: IsotonicRegression | _IdentityCalibrator | Pipeline,
    raw_probabilities: np.ndarray,
) -> np.ndarray:
    raw_probabilities = np.clip(np.asarray(raw_probabilities, dtype=np.float64), 0.0, 1.0)
    if isinstance(calibrator, _IdentityCalibrator):
        return calibrator.predict(raw_probabilities)
    if isinstance(calibrator, IsotonicRegression):
        return calibrator.predict(raw_probabilities)
    return calibrator.predict_proba(raw_probabilities.reshape(-1, 1))[:, 1]


def calibrate_exposure_model(
    model: FittedExposureModel,
    training_matrix: pd.DataFrame,
    *,
    method: CalibrationMethod = "isotonic",
    cal_mask: pd.Series | None = None,
) -> FittedExposureModel:
    """Fit per-horizon calibrators on the validation split (prefit; test never used)."""
    mask = cal_mask if cal_mask is not None else validation_split_mask(training_matrix)
    cal_df = training_matrix.loc[mask]
    if cal_df.empty:
        raise ValueError("No validation rows available for calibration")

    raw_preds = model.predict_raw(cal_df)
    calibrators: dict[int, IsotonicRegression | _IdentityCalibrator | Pipeline] = {}
    for horizon in model.horizons:
        label = exposure_label(horizon)
        calibrators[horizon] = _fit_horizon_calibrator(
            raw_preds[model_prediction_column(horizon)].to_numpy(),
            cal_df[label].to_numpy(),
            method=method,
        )

    return model.with_calibrators(calibrators)


def calibrate_with_sklearn_prefit(
    model: FittedExposureModel,
    training_matrix: pd.DataFrame,
    *,
    method: CalibrationMethod = "isotonic",
    cal_mask: pd.Series | None = None,
) -> FittedExposureModel:
    """Wrap each horizon pipeline in CalibratedClassifierCV(cv='prefit') on validation rows."""
    mask = cal_mask if cal_mask is not None else validation_split_mask(training_matrix)
    cal_df = training_matrix.loc[mask]
    if cal_df.empty:
        raise ValueError("No validation rows available for calibration")

    features = cal_df.loc[:, list(model.feature_columns)]
    calibrated_pipelines: dict[int, CalibratedClassifierCV] = {}
    for horizon in model.horizons:
        label = exposure_label(horizon)
        base = model.pipelines[horizon]
        calibrator = CalibratedClassifierCV(base, method=method, cv="prefit")
        try:
            calibrator.fit(features, cal_df[label])
        except ValueError:
            # Single-class validation slice: keep uncalibrated pipeline.
            calibrated_pipelines[horizon] = base  # type: ignore[assignment]
            continue
        calibrated_pipelines[horizon] = calibrator

    return FittedExposureModel(
        region_id=model.region_id,
        horizons=model.horizons,
        feature_columns=model.feature_columns,
        pipelines=calibrated_pipelines,  # type: ignore[arg-type]
        calibrators=None,
    )


